settings.custom_liquid:
{%- assign price  = product.price -%}
{%- assign seed   = product.id | modulo: 41 -%}

{%- if price < 300000 -%}
  {%- comment -%}Under ₹3,000 — earrings, small studs → 120–200{%- endcomment -%}
  {%- assign loved_count = seed | times: 2 | plus: 120 -%}

{%- elsif price < 800000 -%}
  {%- comment -%}₹3,000–8,000 — chokers, small sets → 70–110{%- endcomment -%}
  {%- assign loved_count = seed | plus: 70 -%}

{%- elsif price < 2000000 -%}
  {%- comment -%}₹8,000–20,000 — necklace sets, haars → 35–74{%- endcomment -%}
  {%- assign loved_count = seed | modulo: 40 | plus: 35 -%}

{%- elsif price < 4000000 -%}
  {%- comment -%}₹20,000–40,000 — bridal sets, mathapattis → 15–34{%- endcomment -%}
  {%- assign loved_count = seed | modulo: 20 | plus: 15 -%}

{%- else -%}
  {%- comment -%}Above ₹40,000 — heavy bridal → 6–17{%- endcomment -%}
  {%- assign loved_count = seed | modulo: 12 | plus: 6 -%}

{%- endif -%}

<style>
  .rt-loved {
    display: flex;
    align-items: center;
    gap: 12px;
    margin: 0 0 14px !important;
  }
  .rt-loved__heart {
    width: 20px;
    height: 20px;
    fill: #D63B3B;
    flex-shrink: 0;
    animation: rt-beat 2s ease-in-out infinite;
    filter: drop-shadow(0 0 5px rgba(214,59,59,0.45));
  }
  @keyframes rt-beat {
    0%,100% { transform: scale(1); }
    8%      { transform: scale(1.38); }
    18%     { transform: scale(1.06); }
    28%     { transform: scale(1.30); }
    38%     { transform: scale(1); }
  }
  .rt-loved__body {
    display: flex;
    align-items: baseline;
    gap: 7px;
    line-height: 1;
  }
  .rt-loved__n {
    font-family: var(--font-body-family, sans-serif);
    font-size: 16px;
    font-weight: 600;
    color: #0a0a0a;
    letter-spacing: 0.01em;
  }
  .rt-loved__label {
    font-family: var(--font-body-family, sans-serif);
    font-size: 10px;
    letter-spacing: 0.18em;
    text-transform: uppercase;
    color: rgba(18,18,18,0.48);
  }
</style>

<div class="rt-loved" aria-label="{{ loved_count }} people love this piece">
  <svg class="rt-loved__heart" viewBox="0 0 24 24" aria-hidden="true">
    <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.499 5.499 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"/>
  </svg>
  <div class="rt-loved__body">
    <span class="rt-loved__n">{{ loved_count }}</span>
    <span class="rt-loved__label">people love this piece</span>
  </div>
</div>

{% if product.metafields.custom.availability %}
  {%- assign is_mto = false -%}
  {%- if product.metafields.custom.availability == 'Made to Order' -%}
    {%- assign is_mto = true -%}
  {%- endif -%}

  <style>
    .rt-av {
      display: flex;
      align-items: center;
      gap: 14px;
      padding: 12px 12px;
      border: 0.5px solid {% if is_mto %}#C9A84C{% else %}#b5b0a9{% endif %};
      width: 100%;
      box-sizing: border-box;
      margin: 2px 0 2px;
    }
    .rt-av__dot {
      width: 6px;
      height: 6px;
      border-radius: 50%;
      flex-shrink: 0;
      background: {% if is_mto %}#C9A84C{% else %}#5a9e72{% endif %};
      animation: rt-pulse 2.4s ease-in-out infinite;
    }
    @keyframes rt-pulse {
      0%, 100% { opacity: 1; }
      50%       { opacity: 0.28; }
    }
    .rt-av__copy { display: flex; flex-direction: column; gap: 3px; }
    .rt-av__lbl {
      font-family: var(--font-body-family, sans-serif);
      font-size: 10px;
      letter-spacing: 0.2em;
      text-transform: uppercase;
      color: #0a0a0a;
      line-height: 1;
    }
    .rt-av__sub {
      font-family: var(--font-body-family, sans-serif);
      font-size: 9px;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      color: #97918a;
      margin-top: 4px;
      line-height: 1;
    }
  </style>

  <div class="rt-av" role="status">
    <span class="rt-av__dot" aria-hidden="true"></span>
    <div class="rt-av__copy">
      <div class="rt-av__lbl">
        {%- if is_mto -%}Crafted for You{%- else -%}Ready to Ship{%- endif -%}
      </div>
      <div class="rt-av__sub">
        {%- if is_mto -%}Made to Order &middot; Ships in 2&ndash;3 weeks
        {%- else -%}Ships in 3&ndash;5 business days
        {%- endif -%}
      </div>
    </div>
  </div>

{% endif %}

{%- assign wa_message = 'Hi, I am interested in ' | append: product.title | url_encode -%}
{%- assign wa_url = 'https://wa.me/919251110762?text=' | append: wa_message -%}

<div class="rng-wa">
  <p class="rng-wa__text">Need assistance, expedited delivery or customisation? <a href="{{ wa_url }}" target="_blank" rel="noopener" class="rng-wa__link">Chat with us</a></p>
</div>

<style>
  .rng-wa {
    margin-top: -1.2rem;
  }
  .rng-wa__text {
    margin: 0;
    font-size: 1.3rem;
    font-style: italic;
    font-weight: 300;
    letter-spacing: 0.01em;
    color: #9c8778;
  }
  .rng-wa__link {
    color: #5c3d2a;
    text-decoration: underline;
    text-underline-offset: 3px;
    text-decoration-thickness: 1px;
  }
  .rng-wa__link:hover {
    color: #3a2418;
  }
</style>

{% comment %} Free Shipping Strip {% endcomment %}
