{%- comment -%}
  Rangtarini — Trust Badges Snippet
  File: snippets/trust-badges.liquid
  Usage: {% render 'trust-badges' %}
  Place this render tag inside your product form block, directly after
  the Add to Cart button in sections/main-product.liquid (or your theme's
  product template file). Search for 'Add to cart' or the submit button
  and paste the render tag immediately below it.
{%- endcomment -%}

{%- liquid
  assign is_alloy       = false
  assign is_silver_925  = false
  assign is_gp_silver   = false

  for col in product.collections
    if col.handle == 'gold-plated-silver-alloy'
      assign is_alloy = true
    endif
    if col.handle == 'pure-silver-925'
      assign is_silver_925 = true
    endif
    if col.handle == 'gold-plated-silver'
      assign is_gp_silver = true
    endif
  endfor

  assign show_hallmark = false
  if is_silver_925 or is_gp_silver
    assign show_hallmark = true
  endif

  assign show_badges = false
  if is_alloy or is_silver_925 or is_gp_silver
    assign show_badges = true
  endif
-%}

