<style>
  .rt-trust-badges {
    display: flex;
    align-items: flex-start;
    justify-content: center;
    gap: 0;
    padding: 2px 0 2px;
    margin-top: 2px;
    border-top: 1px solid rgba(139, 94, 74, 0.15);
  }

  .rt-badge {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 8px;
    flex: 1;
    padding: 0 8px;
    position: relative;
  }

  /* Dividers between badges */
  .rt-badge + .rt-badge::before {
    content: '';
    position: absolute;
    left: 0;
    top: 8px;
    bottom: 8px;
    width: 1px;
    background: rgba(139, 94, 74, 0.2);
  }

  .rt-badge__icon {
    width: 52px;
    height: 52px;
    color: #8B5E4A;
    flex-shrink: 0;
  }

  .rt-badge__icon svg {
    width: 100%;
    height: 100%;
  }

  .rt-badge__label {
    font-family: 'Cormorant Garamond', 'Georgia', serif;
    font-size: 11.5px;
    font-weight: 500;
    line-height: 1.4;
    color: #8B5E4A;
    text-align: center;
    letter-spacing: 0.01em;
  }

  /* Wider screens — give badges a bit more breathing room */
  @media (min-width: 750px) {
    .rt-trust-badges {
      gap: 0;
      padding: 20px 0 6px;
    }

    .rt-badge__icon {
      width: 58px;
      height: 58px;
    }

    .rt-badge__label {
      font-size: 12px;
    }
  }

  /* Narrow product columns on desktop */
  @media (max-width: 480px) {
    .rt-badge__icon {
      width: 44px;
      height: 44px;
    }

    .rt-badge__label {
      font-size: 10.5px;
    }
  }
</style>
{%- endif -%}
